parameters.jsCode:
const item = $input.first().json;
const raw = item.text ?? item.output ?? item.response ?? '';
let messageType = item.messageType ?? 'ticket';

try {
  const parsed = JSON.parse(String(raw));
  if (parsed.messageType) messageType = parsed.messageType;
} catch {
  const lower = String(raw).toLowerCase();
  if (lower.includes('payment')) messageType = 'payment_receipt';
  else if (lower.includes('general')) messageType = 'general';
}

return [{ json: { ...item, messageType } }];

const item = $input.first().json;
const phone = String(item.phone ?? item.From ?? 'whatsapp-unknown').trim();
const flatNumber = item.flatNumber ? String(item.flatNumber).trim() : null;
const messageType = item.messageType ?? 'ticket';
const description = String(item.description ?? '').trim();

return [
  {
    json: {
      ...item,
      portalPayload: {
        societyId: item.societyId,
        flatNumber,
        phone,
        messageType,
        subject:
          item.subject?.trim() ||
          (flatNumber ? `WhatsApp helpdesk — Flat ${flatNumber}` : 'WhatsApp helpdesk ticket'),
        description,
        amount: item.amount ?? null
      }
    }
  }
];
